"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[2739],{2497(e,t,n){n.r(t),n.d(t,{assets:()=>h,contentTitle:()=>a,default:()=>d,frontMatter:()=>s,metadata:()=>r,toc:()=>l});var o=n(4848),i=n(8453);const s={},a="Prologue: The Invisible Cost",r={id:"GameVictory/\u5e8f\u7ae0_\u770b\u4e0d\u898b\u7684\u4ee3\u50f9_v1",title:"Prologue: The Invisible Cost",description:"2:00 AM.",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u5e8f\u7ae0_\u770b\u4e0d\u898b\u7684\u4ee3\u50f9_v1.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u5e8f\u7ae0_\u770b\u4e0d\u898b\u7684\u4ee3\u50f9_v1",permalink:"/MythogenEngine/en/docs/GameVictory/\u5e8f\u7ae0_\u770b\u4e0d\u898b\u7684\u4ee3\u50f9_v1",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Play While Learning",permalink:"/MythogenEngine/en/docs/GameVictory/\u81ea\u5e8f_\u73a9\u4f4f\u5b78_v17"},next:{title:"Chapter 1: The DOS Era: A Clash of Gods",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e00\u7ae0_\u795e\u4ed9\u6253\u67b6\u7684DOS\u6642\u4ee3_v4"}},h={},l=[];function c(e){const t={h1:"h1",header:"header",hr:"hr",img:"img",p:"p",...(0,i.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.header,{children:(0,o.jsx)(t.h1,{id:"prologue-the-invisible-cost",children:"Prologue: The Invisible Cost"})}),"\n",(0,o.jsx)(t.p,{children:"2:00 AM."}),"\n",(0,o.jsx)(t.p,{children:"Perhaps the reader is turning to this page at exactly such a moment. On hand is a Steam Deck, smoothly running some latest AAA Windows game; a charging iPhone nearby lights up with a notification, then quickly goes dark. Outside the window, the city is quiet, but in a data center on the other side of the globe, an entire rack of NVIDIA servers is running day and night with the fan noise of thirty-something degrees Celsius, computing the next set of weights for an AI model. Those chips came from Hsinchu\u2014the ultimate victory of TSMC's 3-nanometer process yield."}),"\n",(0,o.jsx)(t.p,{children:"In this entire scene, everything seems to be taken for granted."}),"\n",(0,o.jsx)(t.p,{children:"But none of it should exist."}),"\n",(0,o.jsx)(t.p,{children:'The Steam Deck is a Linux handheld console; it was never supposed to run Windows games. That this can happen is because a group of people decided to gamble the fate of their company to secretly build a virtual bridge for gamers. The iPhone\'s processor can be mass-produced to the size of your pocket because another group of people was willing to foot the bill for larger, hotter, and more power-hungry chips\u2014those people were PC gamers. NVIDIA was never an "AI company"; it is a company that sells gaming graphics cards. It was only by relying on an entire generation of gamers pursuing extreme graphics to share its ten years of parallel computing R&D costs that it survived until the day ChatGPT was born.'}),"\n",(0,o.jsx)(t.p,{children:"What this book is going to tell is the story behind this entire timeline."}),"\n",(0,o.jsx)(t.hr,{}),"\n",(0,o.jsx)(t.p,{children:"Over the past forty years, from Silicon Valley to Hsinchu, Redmond, Tokyo, and Seoul\u2014every major pivot in global tech hegemony has seemingly been about a CEO's gamble, Wall Street's valuation games, or a new operating system update. But if you stretch the timeline long enough, you will find that there is only one true driving force:"}),"\n",(0,o.jsx)(t.p,{children:"Someone wanted to play a better game."}),"\n",(0,o.jsx)(t.p,{children:"This motivation sounds trivial, even a bit absurd. But it has been the most violent engine of human technological civilization over the past forty years."}),"\n",(0,o.jsx)(t.p,{children:"In order to let them play better, companies went bankrupt, while others came back from the dead. Engineers were forced to rewrite someone else's graphics card drivers; CEOs were forced to gamble their entire company's future on something they never wanted to do in the first place. Industry standards were deliberately strangled, and technical roadmaps were overthrown at the last minute. There were dictatorial CEOs, crazy programmers, and a Japanese old man willing to swallow a five-million-dollar penalty\u2014they had never met each other, and might not even know of each other's existence their whole lives. But every decision they made was reshaping the same invisible chassis."}),"\n",(0,o.jsx)(t.p,{children:"This chassis is the very ground upon which the AI revolution, smartphones, the global semiconductor landscape\u2014and even geopolitics\u2014stand today."}),"\n",(0,o.jsx)(t.p,{children:"It was never rationally planned."}),"\n",(0,o.jsx)(t.p,{children:"It was forced into existence by a group of people who just wanted to play games."}),"\n",(0,o.jsx)(t.hr,{}),"\n",(0,o.jsx)(t.p,{children:"This book will take you back to those scenes."}),"\n",(0,o.jsx)(t.p,{children:"Back to a dim office in the early 1990s, watching Bill Gates personally finalize a partnership that would determine the future of the Windows empire. Back to Tokyo in the spring of 2000, watching a young Jensen Huang walk into Sega's headquarters and say a sentence that even he himself didn't believe would work. Back to a Valve conference room in the 2010s, watching a group of engineers decide that they would make Windows games run on Linux without modifying a single line of Windows source code. Back to a dust-free production line in the Hsinchu Science Park that never stops running, watching the hardest-to-manufacture chips in the world roll out one by one, never missing an appointment."}),"\n",(0,o.jsx)(t.p,{children:"This is also a story about cost."}),"\n",(0,o.jsx)(t.p,{children:'The cost is invisible because it is never written on financial statements. It is hidden in the yield curve of every chip, in every line of reverse-engineered graphics API, and in the fingertips of every gamer who presses "Try Again" at 3:00 AM.'}),"\n",(0,o.jsx)(t.p,{children:"Without these costs, there would be no AI today; nor would there be the iPhone in your pocket, the Steam Deck on your desk, or those GPUs on the other side of the Earth calculating the next sentence for humanity."}),"\n",(0,o.jsx)(t.p,{children:"What this book aims to do is to recalculate this bill, clearly."}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.img,{src:n(8110).A+"",width:"2806",height:"1504"})})]})}function d(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(c,{...e})}):c(e)}},8110(e,t,n){n.d(t,{A:()=>o});const o=n.p+"assets/images/ch00_en-e0ff4636be3deb1838ca9231f88cd6f4.png"},8453(e,t,n){n.d(t,{R:()=>a,x:()=>r});var o=n(6540);const i={},s=o.createContext(i);function a(e){const t=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),o.createElement(s.Provider,{value:t},e.children)}}}]);